// Acepta el formato:
//   ?month=YYYY-MM            (mes natural; obligatorio si no se quiere el actual)
//   ?refresh=1                (ignora caché y regenera)
//
// Default: el mes pasado completo (los días del mes en curso pueden
// estar incompletos y ensucian el análisis comparativo).
const raw = $input.first().json || {};
const q = raw.query || raw.params || {};

function iso(d) { return d.toISOString().slice(0, 10); }
function lastDayOfMonth(y, m) {
  // m es 1..12. Truco: día 0 del mes siguiente = último día del mes actual.
  return new Date(Date.UTC(y, m, 0)).getUTCDate();
}

const MES_NOMBRES = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];

let anio, mes;

if (q.month && /^\d{4}-\d{1,2}$/.test(q.month)) {
  const [y, m] = String(q.month).split('-').map(Number);
  if (m < 1 || m > 12) throw new Error('mes fuera de rango (1..12): ' + m);
  anio = y; mes = m;
} else {
  // Default: mes pasado completo
  const ahora = new Date();
  ahora.setUTCDate(1);
  ahora.setUTCMonth(ahora.getUTCMonth() - 1);
  anio = ahora.getUTCFullYear();
  mes  = ahora.getUTCMonth() + 1;
}

const from  = iso(new Date(Date.UTC(anio, mes - 1, 1)));
const to    = iso(new Date(Date.UTC(anio, mes - 1, lastDayOfMonth(anio, mes))));
const label = `${MES_NOMBRES[mes - 1]} ${anio}`;
// Search query: rango de creación del mes. -subject:"Conversation with"
// excluye los tickets que aún están en el agente IA (ver workflow 28 y 25).
const zendeskQuery = `type:ticket created>=${from} created<=${to} -subject:"Conversation with"`;

const forceRefresh = String(q.refresh || '') === '1' || q.refresh === 'true';

return [{ json: {
  anio, mes,
  fecha_desde: from,
  fecha_hasta: to,
  label,
  forceRefresh,
  zendeskQuery
} }];

// Rama TRUE — fila cacheada en Supabase. Se desempaqueta al shape
// del front (mismo que el de generación al vuelo).
const meta = $('Validar rango').first().json;
const raw  = $input.first().json;
const row  = Array.isArray(raw) ? raw[0] : raw;

function parseArr(v) {
  if (Array.isArray(v)) return v;
  if (typeof v === 'string') {
    try { const p = JSON.parse(v); return Array.isArray(p) ? p : []; } catch (_) { return []; }
  }
  return [];
}

return [{ json: {
  success: true,
  cached:  true,
  rango:   { from: row.fecha_desde, to: row.fecha_hasta, label: meta.label },
  anio:    meta.anio,
  mes:     meta.mes,
  total:   row.total_tickets || 0,
  porTipo:    parseArr(row.por_tipo),
  porEntorno: parseArr(row.por_entorno),
  porModulo:  parseArr(row.por_modulo),
  porDia:     parseArr(row.por_dia),
  porEstado:  parseArr(row.por_estado),
  topClientes:parseArr(row.top_clientes),
  tickets:    parseArr(row.tickets),
  resumen_markdown: row.resumen_markdown || '',
  modelo:     row.modelo || null,
  generado_en:    row.created_at,
  actualizado_en: row.updated_at
} }];

// Agregación pesada del análisis mensual:
//  - normaliza tickets (extrae custom fields tipo/entorno/modulo, defensivo
//    para multi-select arrays como en workflow 28).
//  - filtra los de "Conversation with" (backup del operador NOT del query).
//  - calcula breakdowns por tipo/entorno/módulo (todo se cuenta por
//    elemento, no por combinación, ver cuentaArr).
//  - distribución diaria 1..31 (para gráfica/heatmap del front).
//  - distribución por estado (open/pending/solved/closed).
//  - top clientes por organization_id: cuenta + módulos predominantes
//    + tipos predominantes (los IDs se resuelven a nombres en el siguiente
//    nodo, este sólo agrega).
//  - patrones recurrentes en el subject (frecuencia de keywords / topics)
//    extraídos como bigramas — útil para que GPT detecte temas.

const CUSTOM_FIELD_IDS = {
  tipo:    26672700540829,
  entorno: 27376906089629,
  modulo:  27243772817053
};

function extraerCustomFieldArr(t, id) {
  if (id == null) return [];
  const fuentes = [t.custom_fields, t.fields].filter(Array.isArray);
  for (const arr of fuentes) {
    const cf = arr.find(c => c && (c.id === id || String(c.id) === String(id)));
    if (!cf) continue;
    const v = cf.value;
    if (v == null || v === '') return [];
    if (Array.isArray(v)) return v.map(x => String(x).trim()).filter(Boolean);
    return [String(v).trim()];
  }
  return [];
}

const meta = $('Validar rango').first().json;
const rawTickets = ($input.all() || []).map(it => it.json).filter(Boolean);

const norm = rawTickets.map(t => {
  const tipos    = extraerCustomFieldArr(t, CUSTOM_FIELD_IDS.tipo);
  const entornos = extraerCustomFieldArr(t, CUSTOM_FIELD_IDS.entorno);
  const modulos  = extraerCustomFieldArr(t, CUSTOM_FIELD_IDS.modulo);
  return {
    id:      t.id,
    subject: t.subject || t.title || t.descripcion || '(sin título)',
    status:  t.status || null,
    created_at: t.created_at || t.createdAt || null,
    organization_id: t.organization_id || null,
    requester_id:    t.requester_id    || null,
    tipo:    tipos[0]    || 'Sin tipo',
    entorno: entornos[0] || 'Sin entorno',
    modulo:  modulos.length ? modulos.join(' · ') : 'Sin módulo',
    tipos:    tipos.length    ? tipos    : ['Sin tipo'],
    entornos: entornos.length ? entornos : ['Sin entorno'],
    modulos:  modulos.length  ? modulos  : ['Sin módulo']
  };
}).filter(t => {
  const s = String(t.subject || '').trim().toLowerCase();
  return !s.startsWith('conversation with');
});

function cuentaArr(arr, key) {
  const map = new Map();
  for (const x of arr) {
    for (const v of (x[key] || [])) {
      map.set(v, (map.get(v) || 0) + 1);
    }
  }
  return [...map.entries()]
    .map(([nombre, count]) => ({ nombre, count }))
    .sort((a, b) => b.count - a.count);
}

const porTipo    = cuentaArr(norm, 'tipos');
const porEntorno = cuentaArr(norm, 'entornos');
const porModulo  = cuentaArr(norm, 'modulos');

// Distribución diaria (1..31). Inicializamos a 0 todos los días que el
// mes natural realmente tiene (último día del mes).
const lastDay = new Date(Date.UTC(meta.anio, meta.mes, 0)).getUTCDate();
const diaCount = new Array(lastDay + 1).fill(0); // index 0 ignorado, 1..lastDay
for (const t of norm) {
  if (!t.created_at) continue;
  const d = new Date(t.created_at);
  if (isNaN(d.getTime())) continue;
  // Usamos UTC del created_at para no mezclar zonas. Suficiente para
  // distribución diaria — la diferencia ±1 día por TZ no afecta al
  // patrón de fondo.
  if (d.getUTCFullYear() === meta.anio && d.getUTCMonth() + 1 === meta.mes) {
    const day = d.getUTCDate();
    if (day >= 1 && day <= lastDay) diaCount[day]++;
  }
}
const porDia = [];
for (let i = 1; i <= lastDay; i++) porDia.push({ dia: i, count: diaCount[i] });

// Por estado (open/pending/solved/closed/etc.)
const estadoMap = new Map();
for (const t of norm) {
  const k = t.status || 'sin_estado';
  estadoMap.set(k, (estadoMap.get(k) || 0) + 1);
}
const porEstado = [...estadoMap.entries()]
  .map(([estado, count]) => ({ estado, count }))
  .sort((a, b) => b.count - a.count);

// Top clientes (por organization_id). Aún no tenemos el nombre, sólo el id.
// El siguiente nodo HTTP los resuelve a nombres.
const orgMap = new Map();
for (const t of norm) {
  const orgId = t.organization_id;
  if (!orgId) continue;
  let entry = orgMap.get(orgId);
  if (!entry) {
    entry = {
      organization_id: orgId,
      count: 0,
      modulos: new Map(),  // modulo → count
      tipos:   new Map(),
      entornos:new Map(),
      ejemplos: []
    };
    orgMap.set(orgId, entry);
  }
  entry.count++;
  for (const m of t.modulos) entry.modulos.set(m, (entry.modulos.get(m) || 0) + 1);
  for (const ti of t.tipos)  entry.tipos.set(ti, (entry.tipos.get(ti) || 0) + 1);
  for (const e of t.entornos)entry.entornos.set(e, (entry.entornos.get(e) || 0) + 1);
  if (entry.ejemplos.length < 3) entry.ejemplos.push(t.subject);
}
const TOP_N = 15;
const topClientesRaw = [...orgMap.values()]
  .sort((a, b) => b.count - a.count)
  .slice(0, TOP_N)
  .map(e => ({
    organization_id: e.organization_id,
    organization_name: null,  // se rellena en el siguiente nodo
    count: e.count,
    modulos:  [...e.modulos].sort((a,b)=>b[1]-a[1]).slice(0,3).map(([n,c])=>({nombre:n,count:c})),
    tipos:    [...e.tipos].sort((a,b)=>b[1]-a[1]).slice(0,3).map(([n,c])=>({nombre:n,count:c})),
    entornos: [...e.entornos].sort((a,b)=>b[1]-a[1]).slice(0,3).map(([n,c])=>({nombre:n,count:c})),
    ejemplos: e.ejemplos
  }));

// Lista única de organization_id no nulos para el batch a Zendesk.
const __org_ids = [...new Set(topClientesRaw.map(c => c.organization_id))];

return [{ json: {
  anio: meta.anio,
  mes:  meta.mes,
  rango: { from: meta.fecha_desde, to: meta.fecha_hasta, label: meta.label },
  total: norm.length,
  porTipo, porEntorno, porModulo,
  porDia, porEstado,
  topClientesRaw,   // sin nombres aún
  tickets: norm,
  __org_ids
} }];

// Mergea los nombres de organización en topClientes y en la lista de
// tickets. Mismo patrón que el workflow 25 (heatmap).
const aggregated = $('Agregar datos').first().json || {};
const orgsResp   = $input.first().json || {};
const orgsArr    = Array.isArray(orgsResp.organizations) ? orgsResp.organizations : [];
const orgMap     = new Map(orgsArr.map(o => [o.id, o.name]));

const topClientes = (aggregated.topClientesRaw || []).map(c => ({
  ...c,
  organization_name: orgMap.get(c.organization_id) || `(org ${c.organization_id})`
}));

const tickets = (aggregated.tickets || []).map(t => ({
  ...t,
  organization_name: t.organization_id ? (orgMap.get(t.organization_id) || null) : null
}));

return [{ json: {
  anio:   aggregated.anio,
  mes:    aggregated.mes,
  rango:  aggregated.rango,
  total:  aggregated.total,
  porTipo:    aggregated.porTipo,
  porEntorno: aggregated.porEntorno,
  porModulo:  aggregated.porModulo,
  porDia:     aggregated.porDia,
  porEstado:  aggregated.porEstado,
  topClientes,
  tickets
} }];

// Construye el prompt MENSUAL con todo el material agregado.
// Estrategia para no reventar tokens: pasamos las TABLAS agregadas al
// completo (cuestan poco) y de los tickets brutos sólo una muestra
// representativa por módulo. GPT puede entonces detectar patrones reales
// con ejemplos concretos en mano sin que le tengamos que dar 300 líneas.

const d = $input.first().json;

function listaBreakdown(arr, n) {
  return (arr || []).slice(0, n || 10)
    .map(x => `  - ${x.nombre || x.estado}: ${x.count}`).join('\n');
}
function listaTopClientes(arr, n) {
  return (arr || []).slice(0, n || 10).map((c, i) => {
    const mods = (c.modulos || []).map(m => `${m.nombre} (${m.count})`).join(', ');
    const tips = (c.tipos   || []).map(t => `${t.nombre} (${t.count})`).join(', ');
    const ejs  = (c.ejemplos || []).slice(0, 2).map(s => `      · ${s}`).join('\n');
    return `  ${i+1}. **${c.organization_name}** — ${c.count} tickets\n       Módulos: ${mods || '—'}\n       Tipos: ${tips || '—'}\n${ejs}`;
  }).join('\n');
}
function listaPorDia(arr) {
  return (arr || []).map(x => `${String(x.dia).padStart(2,'0')}=${x.count}`).join(', ');
}
function muestraTickets(tickets, porModulo) {
  // Para cada uno de los top 5 módulos, sacamos hasta 5 tickets de ejemplo.
  // Total máximo: 25 ejemplos, suficiente para que GPT vea casos concretos.
  const out = [];
  const topMods = (porModulo || []).slice(0, 5).map(m => m.nombre);
  for (const m of topMods) {
    const sample = (tickets || []).filter(t => (t.modulos || []).includes(m)).slice(0, 5);
    if (!sample.length) continue;
    out.push(`\n### Ejemplos de "${m}":`);
    for (const t of sample) {
      const org = t.organization_name ? ` [${t.organization_name}]` : '';
      out.push(`- [#${t.id}]${org} ${t.subject}`);
    }
  }
  return out.join('\n');
}

const superPrompt = `Eres un Senior Support Manager + Product Analyst en Yurest, una\
plataforma SaaS de gestión integral para hostelería. Te paso TODOS los\
tickets cerrados del MES y agregados ya calculados (por tipo, entorno,\
módulo, día, cliente). Tu trabajo es producir un INFORME MENSUAL\
ejecutivo profundo y accionable para la dirección de Producto + Soporte.\
\n\
No te limites a enumerar. ANALIZA: detecta patrones, identifica clientes\
en riesgo, módulos en mal estado, errores recurrentes, oportunidades\
de mejora. Sé directo y útil — esto se va a leer en una reunión de\
dirección.\n\n\
## DATOS DEL PERIODO\n\
- **Periodo**: ${d.rango.label} (${d.rango.from} → ${d.rango.to})\n\
- **Tickets totales**: ${d.total}\n\n\
### Distribución por tipo (top 10)\n${listaBreakdown(d.porTipo, 10)}\n\n\
### Distribución por entorno (top 10)\n${listaBreakdown(d.porEntorno, 10)}\n\n\
### Distribución por módulo (top 12) — los multi-módulo cuentan en cada uno\n${listaBreakdown(d.porModulo, 12)}\n\n\
### Distribución por estado al cierre del mes\n${listaBreakdown(d.porEstado, 10)}\n\n\
### Volumen diario (día=count) — ¿hay picos?\n${listaPorDia(d.porDia)}\n\n\
### Top clientes con más tickets este mes (top 10)\n${listaTopClientes(d.topClientes, 10)}\n\n\
### Muestra de tickets por módulo más activo (para que veas casos reales)${muestraTickets(d.tickets, d.porModulo)}\n\n\
## ESTRUCTURA DEL INFORME\n\
Responde **en español**, en formato Markdown, siguiendo este esquema\
exacto. No te saltes ninguna sección:\n\n\
### 🩺 Diagnóstico ejecutivo\n\
Un párrafo (4-6 líneas) con la lectura de fondo del mes — volumen,\
salud general del producto, cuál fue la métrica más preocupante,\
cuál la más positiva. Trata el mes como un todo, no enumeres aún.\n\n\
### 📊 Métricas clave\n\
Lista de 5-7 bullets cuantitativos: volumen total, top tipo y %,\
top módulo y %, % de tickets resueltos vs abiertos, día/rango con\
más actividad, etc. Cada bullet con un dato concreto.\n\n\
### 🔥 Patrones recurrentes\n\
Identifica 4-6 patrones reales que VES en los datos (no inventes —\
basados en los asuntos de muestra). Cada uno: **negrita el patrón**,\
2-3 líneas explicando, ejemplo de cliente afectado si aplica, y\
entre paréntesis cuántos tickets aproximados lo tocan.\n\n\
### 🧩 Salud por módulo\n\
Para los TOP 5 módulos: **negrita el módulo**, una línea con su\
volumen y un veredicto (🟢 estable / 🟡 atención / 🔴 crítico) +\
una frase explicando POR QUÉ ese veredicto basándote en el tipo de\
incidencias y los clientes afectados.\n\n\
### 🏢 Top clientes — clientes en foco\n\
Tabla markdown de los 10 clientes con más tickets:\n\
| Cliente | Tickets | Módulos calientes | ¿Riesgo de churn? |\n\
| --- | ---: | --- | :---: |\n\
[10 filas]\n\
\
La columna "Riesgo de churn" es tu juicio: ⚪️ ninguno / 🟡 vigilar /\
🔴 alto. Justifícalo con un comentario corto debajo de la tabla\
para los que marques 🔴.\n\n\
### ⚠️ Errores e incidencias críticas\n\
De los tipos \`incidencia_dev\` y \`incidencia_soporte\`, identifica\
3-5 errores que se REPITEN en varios clientes (no son casos puntuales).\
Descríbelos con un nombre cortito + 1-2 líneas explicando + clientes\
afectados.\n\n\
### 🎯 Recomendaciones\n\
3-4 acciones concretas y accionables, una por área:\n\
- 🛠️ **Soporte**: qué hacer la próxima semana.\n\
- 💻 **Producto**: qué bug arreglar o feature revisar.\n\
- 📚 **Documentación**: qué FAQ o guía actualizar.\n\
- 🤝 **Customer Success**: qué clientes contactar proactivamente.\n\n\
### 📈 Tendencia y comparativa\n\
Si detectas patrones que sugieren tendencia (un módulo creciendo en\
incidencias, un cliente que está empeorando, picos en ciertos días),\
señálalo aquí en 2-3 bullets. Si no hay tendencia clara, di\
explícitamente "sin tendencia significativa con un solo mes de datos".\n\n\
### Tono\n\
Claro, ejecutivo, directo. Cero relleno. Si una sección no tiene\
material real (ej: 0 incidencias_dev), di "sin material" en vez de\
inventar. Usa los emojis sólo en los headings y en los chips de\
veredicto (🟢🟡🔴⚪️).`;

return [{ json: {
  prompt_final: superPrompt,
  anio: d.anio,
  mes:  d.mes,
  rango: d.rango,
  total: d.total,
  porTipo: d.porTipo,
  porEntorno: d.porEntorno,
  porModulo: d.porModulo,
  porDia: d.porDia,
  porEstado: d.porEstado,
  topClientes: d.topClientes,
  tickets: d.tickets
} }];

// Combina la respuesta de GPT con los datos estructurados ya calculados.
const prep   = $('Preparar prompt').first().json;
const aiResp = $input.first().json || {};

function extractText(c) {
  if (c == null) return '';
  if (typeof c === 'string') return c;
  if (Array.isArray(c)) return c.map(extractText).filter(Boolean).join('');
  if (typeof c === 'object') {
    if (typeof c.text === 'string')    return c.text;
    if (typeof c.content === 'string') return c.content;
    if (typeof c.output === 'string')  return c.output;
    if (typeof c.value === 'string')   return c.value;
    if (c.text)    return extractText(c.text);
    if (c.content) return extractText(c.content);
    if (c.output)  return extractText(c.output);
  }
  return '';
}

let resumenMd = '';
if (typeof aiResp === 'string') {
  resumenMd = aiResp;
} else if (Array.isArray(aiResp.choices) && aiResp.choices[0]?.message?.content) {
  resumenMd = extractText(aiResp.choices[0].message.content);
} else if (aiResp.message && aiResp.message.content) {
  resumenMd = extractText(aiResp.message.content);
} else if (aiResp.content) {
  resumenMd = extractText(aiResp.content);
} else if (aiResp.text) {
  resumenMd = extractText(aiResp.text);
} else if (aiResp.output) {
  resumenMd = extractText(aiResp.output);
}

if (!resumenMd || typeof resumenMd !== 'string') {
  try {
    resumenMd = '⚠️ Respuesta inesperada de OpenAI:\n```json\n' +
      JSON.stringify(aiResp, null, 2).slice(0, 800) + '\n```';
  } catch (_) { resumenMd = '(sin resumen)'; }
}
resumenMd = resumenMd
  .replace(/^```(?:markdown|md)?\s*\n?/i, '')
  .replace(/\n?```\s*$/i, '')
  .trim();

return [{ json: {
  success: true,
  cached:  false,
  rango:   prep.rango,
  anio:    prep.anio,
  mes:     prep.mes,
  total:   prep.total,
  porTipo:    prep.porTipo,
  porEntorno: prep.porEntorno,
  porModulo:  prep.porModulo,
  porDia:     prep.porDia,
  porEstado:  prep.porEstado,
  topClientes:prep.topClientes,
  tickets:    prep.tickets,
  resumen_markdown: resumenMd,
  modelo: 'gpt-4o'
} }];

// Devuelve el payload de Formatear resultado al front, ignorando la
// respuesta del UPSERT (fire-and-forget). Mismo patrón que el workflow 28.
return [{ json: $('Formatear resultado').first().json }];
